/**
 * Redis Configuration
 *
 * Redis client singleton for E-Menum using ioredis.
 * Provides caching, session storage, and BullMQ queue support.
 *
 * @module config/redis
 */

import Redis, { RedisOptions } from 'ioredis';
import { env, isDevelopment } from '@/config/env';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * Redis connection status
 */
export type RedisConnectionStatus = 'connecting' | 'connect' | 'ready' | 'close' | 'reconnecting' | 'end' | 'error';

/**
 * Redis key options for operations
 */
export interface RedisKeyOptions {
  /** Time to live in seconds */
  ttl?: number;
  /** Whether to return the old value on update */
  returnOld?: boolean;
}

/**
 * Redis cache item with metadata
 */
export interface CacheItem<T = unknown> {
  data: T;
  cachedAt: string;
  expiresAt?: string;
}

// -----------------------------------------------------------------------------
// Global Declaration
// -----------------------------------------------------------------------------

/**
 * Global Redis instance declaration for hot reload support in development.
 * This prevents connection exhaustion during development with hot reloading.
 */
declare global {
  // eslint-disable-next-line no-var
  var redis: Redis | undefined;
}

// -----------------------------------------------------------------------------
// Redis Client Configuration
// -----------------------------------------------------------------------------

/**
 * Parses Redis URL and returns connection options
 */
function parseRedisUrl(url: string): RedisOptions {
  const redisUrl = new URL(url);

  const options: RedisOptions = {
    host: redisUrl.hostname,
    port: parseInt(redisUrl.port || '6379', 10),
    keyPrefix: env.REDIS_PREFIX,
    maxRetriesPerRequest: 3,
    retryStrategy(times: number): number | void {
      if (times > 10) {
        // Stop retrying after 10 attempts
        return undefined;
      }
      // Exponential backoff: min 50ms, max 2s
      return Math.min(times * 50, 2000);
    },
    reconnectOnError(err: Error): boolean | 1 | 2 {
      const targetErrors = ['READONLY', 'ECONNRESET', 'ETIMEDOUT'];
      return targetErrors.some((e) => err.message.includes(e));
    },
    lazyConnect: true, // Don't connect immediately
    enableReadyCheck: true,
    showFriendlyErrorStack: isDevelopment(),
  };

  // Add password if provided
  if (redisUrl.password) {
    options.password = redisUrl.password;
  }

  // Add username if provided (Redis 6+ ACL)
  if (redisUrl.username) {
    options.username = redisUrl.username;
  }

  // Add database number if provided
  if (redisUrl.pathname && redisUrl.pathname.length > 1) {
    options.db = parseInt(redisUrl.pathname.slice(1), 10);
  }

  return options;
}

/**
 * Creates a configured Redis client instance
 */
function createRedisClient(): Redis {
  const options = parseRedisUrl(env.REDIS_URL);

  const client = new Redis(options);

  // Connection event handlers
  client.on('connect', () => {
    // eslint-disable-next-line no-console
    console.log('[Redis] Connecting...');
  });

  client.on('ready', () => {
    // eslint-disable-next-line no-console
    console.log('[Redis] Connected and ready');
  });

  client.on('close', () => {
    // eslint-disable-next-line no-console
    console.log('[Redis] Connection closed');
  });

  client.on('reconnecting', () => {
    // eslint-disable-next-line no-console
    console.log('[Redis] Reconnecting...');
  });

  client.on('error', (err: Error) => {
    // eslint-disable-next-line no-console
    console.error('[Redis] Error:', err.message);
  });

  if (isDevelopment()) {
    client.on('end', () => {
      // eslint-disable-next-line no-console
      console.log('[Redis] Connection ended');
    });
  }

  return client;
}

// -----------------------------------------------------------------------------
// Singleton Export
// -----------------------------------------------------------------------------

/**
 * Redis client singleton instance.
 *
 * In development, the client is stored on globalThis to prevent
 * connection exhaustion during hot module reloading (HMR).
 *
 * In production, a new client is created once at startup.
 *
 * @example
 * ```typescript
 * import { redis } from '@/config/redis';
 *
 * // Simple operations
 * await redis.set('key', 'value');
 * const value = await redis.get('key');
 *
 * // With TTL (seconds)
 * await redis.setex('session:123', 3600, JSON.stringify(sessionData));
 *
 * // Hash operations
 * await redis.hset('user:123', 'name', 'John');
 * const name = await redis.hget('user:123', 'name');
 * ```
 */
export const redis = globalThis.redis ?? createRedisClient();

// Store on globalThis in development for HMR support
if (isDevelopment()) {
  globalThis.redis = redis;
}

// -----------------------------------------------------------------------------
// Connection Management
// -----------------------------------------------------------------------------

/**
 * Connects to Redis server.
 * Call this during application startup to verify connectivity.
 *
 * @throws {Error} When Redis connection fails
 */
export async function connectRedis(): Promise<void> {
  try {
    await redis.connect();
    // eslint-disable-next-line no-console
    console.log('[Redis] Connected successfully');
  } catch (error) {
    // Ignore if already connected
    if ((error as Error).message?.includes('already')) {
      return;
    }
    // eslint-disable-next-line no-console
    console.error('[Redis] Connection failed:', error);
    throw error;
  }
}

/**
 * Disconnects from Redis server.
 * Call this during graceful shutdown.
 */
export async function disconnectRedis(): Promise<void> {
  try {
    await redis.quit();
    // eslint-disable-next-line no-console
    console.log('[Redis] Disconnected successfully');
  } catch (error) {
    // Force disconnect if quit fails
    redis.disconnect();
    // eslint-disable-next-line no-console
    console.error('[Redis] Disconnect error (forced):', error);
  }
}

/**
 * Checks Redis connectivity by running a PING command.
 * Useful for health checks and readiness probes.
 *
 * @returns True if Redis is accessible, false otherwise
 */
export async function isRedisHealthy(): Promise<boolean> {
  try {
    const pong = await redis.ping();
    return pong === 'PONG';
  } catch {
    return false;
  }
}

/**
 * Gets current Redis connection status
 *
 * @returns Current connection status
 */
export function getRedisStatus(): RedisConnectionStatus {
  return redis.status as RedisConnectionStatus;
}

// -----------------------------------------------------------------------------
// Cache Helpers
// -----------------------------------------------------------------------------

/**
 * Gets a cached value with JSON parsing.
 *
 * @param key - Cache key (prefix is automatically added)
 * @returns Parsed value or null if not found
 *
 * @example
 * ```typescript
 * const user = await getCache<User>('user:123');
 * if (user) {
 *   console.log(user.name);
 * }
 * ```
 */
export async function getCache<T>(key: string): Promise<T | null> {
  const value = await redis.get(key);
  if (!value) {
    return null;
  }

  try {
    const item = JSON.parse(value) as CacheItem<T>;
    return item.data;
  } catch {
    // If not valid JSON, return as-is (legacy support)
    return value as unknown as T;
  }
}

/**
 * Sets a cache value with JSON serialization.
 *
 * @param key - Cache key (prefix is automatically added)
 * @param value - Value to cache
 * @param options - Cache options (TTL, etc.)
 *
 * @example
 * ```typescript
 * await setCache('user:123', userData, { ttl: 3600 }); // 1 hour TTL
 * await setCache('config', configData); // No expiry
 * ```
 */
export async function setCache<T>(key: string, value: T, options?: RedisKeyOptions): Promise<void> {
  const item: CacheItem<T> = {
    data: value,
    cachedAt: new Date().toISOString(),
    expiresAt: options?.ttl ? new Date(Date.now() + options.ttl * 1000).toISOString() : undefined,
  };

  const serialized = JSON.stringify(item);

  if (options?.ttl) {
    await redis.setex(key, options.ttl, serialized);
  } else {
    await redis.set(key, serialized);
  }
}

/**
 * Deletes a cached value.
 *
 * @param key - Cache key (prefix is automatically added)
 * @returns Number of keys deleted
 */
export async function deleteCache(key: string): Promise<number> {
  return redis.del(key);
}

/**
 * Deletes all cached values matching a pattern.
 *
 * @param pattern - Key pattern (e.g., 'user:*')
 * @returns Number of keys deleted
 *
 * @example
 * ```typescript
 * // Delete all user caches
 * await deleteCachePattern('user:*');
 *
 * // Delete all session caches
 * await deleteCachePattern('session:*');
 * ```
 */
export async function deleteCachePattern(pattern: string): Promise<number> {
  // Use SCAN to find keys (better for large datasets)
  const prefixedPattern = env.REDIS_PREFIX + pattern;
  const stream = redis.scanStream({ match: prefixedPattern });

  let deletedCount = 0;

  return new Promise((resolve, reject) => {
    stream.on('data', async (keys: string[]) => {
      if (keys.length > 0) {
        // Remove prefix from keys since redis.del will add it back
        const unprefixedKeys = keys.map((k) => k.replace(env.REDIS_PREFIX, ''));
        const deleted = await redis.del(...unprefixedKeys);
        deletedCount += deleted;
      }
    });

    stream.on('end', () => resolve(deletedCount));
    stream.on('error', reject);
  });
}

/**
 * Checks if a cache key exists.
 *
 * @param key - Cache key to check
 * @returns True if key exists
 */
export async function cacheExists(key: string): Promise<boolean> {
  const exists = await redis.exists(key);
  return exists === 1;
}

/**
 * Gets remaining TTL for a key in seconds.
 *
 * @param key - Cache key
 * @returns TTL in seconds, -1 if no expiry, -2 if key doesn't exist
 */
export async function getCacheTtl(key: string): Promise<number> {
  return redis.ttl(key);
}

// -----------------------------------------------------------------------------
// Lock Helpers (for distributed locking)
// -----------------------------------------------------------------------------

/**
 * Acquires a distributed lock.
 *
 * @param lockKey - Unique lock identifier
 * @param ttlSeconds - Lock expiration in seconds (default: 30)
 * @returns Lock token if acquired, null if lock is held by another process
 *
 * @example
 * ```typescript
 * const lockToken = await acquireLock('order:process:123', 60);
 * if (lockToken) {
 *   try {
 *     // Process order...
 *   } finally {
 *     await releaseLock('order:process:123', lockToken);
 *   }
 * }
 * ```
 */
export async function acquireLock(lockKey: string, ttlSeconds = 30): Promise<string | null> {
  const token = `${Date.now()}-${Math.random().toString(36).slice(2)}`;
  const key = `lock:${lockKey}`;

  // SET NX EX - Set if not exists with expiry
  const result = await redis.set(key, token, 'EX', ttlSeconds, 'NX');

  return result === 'OK' ? token : null;
}

/**
 * Releases a distributed lock.
 *
 * @param lockKey - Lock identifier
 * @param token - Lock token returned from acquireLock
 * @returns True if lock was released, false if token didn't match
 */
export async function releaseLock(lockKey: string, token: string): Promise<boolean> {
  const key = `lock:${lockKey}`;

  // Lua script to ensure we only delete if token matches (atomic operation)
  const luaScript = `
    if redis.call("get", KEYS[1]) == ARGV[1] then
      return redis.call("del", KEYS[1])
    else
      return 0
    end
  `;

  const result = await redis.eval(luaScript, 1, key, token);
  return result === 1;
}

// -----------------------------------------------------------------------------
// Rate Limiting Helpers
// -----------------------------------------------------------------------------

/**
 * Checks and increments a rate limit counter.
 *
 * @param key - Rate limit key (e.g., 'ratelimit:ip:192.168.1.1')
 * @param limit - Maximum allowed requests
 * @param windowSeconds - Time window in seconds
 * @returns Object with allowed status and remaining count
 *
 * @example
 * ```typescript
 * const { allowed, remaining, resetAt } = await checkRateLimit(
 *   `api:user:${userId}`,
 *   100,  // 100 requests
 *   60    // per minute
 * );
 *
 * if (!allowed) {
 *   throw new AppException('RATE_LIMIT_EXCEEDED', 429);
 * }
 * ```
 */
export async function checkRateLimit(
  key: string,
  limit: number,
  windowSeconds: number
): Promise<{ allowed: boolean; remaining: number; resetAt: Date }> {
  const now = Date.now();
  const windowStart = now - windowSeconds * 1000;
  const resetAt = new Date(now + windowSeconds * 1000);

  // Use sorted set for sliding window rate limiting
  const multi = redis.multi();
  multi.zremrangebyscore(key, 0, windowStart);
  multi.zadd(key, now.toString(), now.toString());
  multi.zcard(key);
  multi.expire(key, windowSeconds);

  const results = await multi.exec();

  if (!results) {
    return { allowed: true, remaining: limit, resetAt };
  }

  const count = (results[2]?.[1] as number) || 0;
  const allowed = count <= limit;
  const remaining = Math.max(0, limit - count);

  return { allowed, remaining, resetAt };
}

// -----------------------------------------------------------------------------
// Pub/Sub Helpers
// -----------------------------------------------------------------------------

/**
 * Creates a dedicated Redis client for subscriptions.
 * Pub/Sub requires a separate connection from the main client.
 *
 * @returns New Redis client for subscriptions
 *
 * @example
 * ```typescript
 * const subscriber = createSubscriber();
 *
 * subscriber.subscribe('orders', (err, count) => {
 *   console.log(`Subscribed to ${count} channels`);
 * });
 *
 * subscriber.on('message', (channel, message) => {
 *   console.log(`Received ${message} from ${channel}`);
 * });
 * ```
 */
export function createSubscriber(): Redis {
  return redis.duplicate();
}

/**
 * Publishes a message to a channel.
 *
 * @param channel - Channel name
 * @param message - Message to publish (will be JSON stringified if object)
 * @returns Number of subscribers that received the message
 */
export async function publishMessage(channel: string, message: unknown): Promise<number> {
  const payload = typeof message === 'string' ? message : JSON.stringify(message);
  return redis.publish(channel, payload);
}

// -----------------------------------------------------------------------------
// BullMQ Connection Export
// -----------------------------------------------------------------------------

/**
 * Gets Redis connection options for BullMQ queues.
 * BullMQ requires plain connection options, not an ioredis instance.
 *
 * @returns Redis connection options for BullMQ
 *
 * @example
 * ```typescript
 * import { Queue, Worker } from 'bullmq';
 * import { getBullMQConnection } from '@/config/redis';
 *
 * const emailQueue = new Queue('email', {
 *   connection: getBullMQConnection()
 * });
 *
 * const worker = new Worker('email', async (job) => {
 *   // Process job...
 * }, { connection: getBullMQConnection() });
 * ```
 */
export function getBullMQConnection(): RedisOptions {
  return parseRedisUrl(env.REDIS_URL);
}
